import React, {Component} from 'react';
import PropTypes from 'prop-types';
import CssBaseline from '@material-ui/core/CssBaseline';
import {PersonAddRounded}from '@material-ui/icons';
import {Typography, Grid, Paper, FormControl, Snackbar, FormControlLabel, Checkbox, Button, Avatar, Input, InputLabel} from '@material-ui/core';
import withStyles from '@material-ui/core/styles/withStyles';
import {Link} from 'react-router-dom';
import ls from 'local-storage';
import Snack from '../Snack'
import AuthComp from './AuthComp'
import {FaFacebookF, FaGoogle, FaGooglePlusG} from 'react-icons/fa'
import firebase from 'firebase';
import {SetUser} from '../../store'
import {connect} from 'react-redux'
// const { classes } = props;
var validator = require("email-validator");

const styles = theme => ({
  main: {
    width: 'auto',
    display: 'block', // Fix IE 11 issue.
    marginLeft: theme.spacing.unit * 3,
    marginRight: theme.spacing.unit * 3,
    [theme.breakpoints.up(400 + theme.spacing.unit * 3 * 2)]: {
      width: 400,
      marginLeft: 'auto',
      marginRight: 'auto',
    },
  },
  paper: {
    marginTop: 90,
    display: 'flex',
    flexDirection: 'column',
    backgroundColor:'# style={{}}',
    alignItems: 'center',
    padding: `${theme.spacing.unit * 2}px ${theme.spacing.unit * 3}px ${theme.spacing.unit * 3}px`,
  },
  avatar: {
    margin: theme.spacing.unit,
    backgroundColor: theme.palette.secondary.main,
  },
  form: {
    width: '100%', // Fix IE 11 issue.
    marginTop: theme.spacing.unit,
  },
  submit: {
    marginTop: theme.spacing.unit * 3,
  },
});

class Login extends Component {
  
  constructor(props) {
    super(props)
    this.state = {
      email: '',
      password: '',
      name: '',
      user: false,
      snack: false
    }

  }
  componentDidMount(){
    if(ls.get('user')) {
      this.props.history.push('/home#/himnos')
    } 
  }

  

  createDatabaseUser(user) {
    console.log(user.uid)
    var obj = {
        name : this.state.name,
        email : this.state.email,
        uid: user.uid
    }
      firebase.database().ref(`users/${user.uid}`).push(obj)
      this.props.SetUser(obj)
  }

  signUp = () => {
    if(validator.validate(this.state.email)) {
      firebase.auth().createUserWithEmailAndPassword(this.state.email, this.state.password).then((res)=> {
        console.log(res)
        ls.set('user', res)
          this.createDatabaseUser(res.user)
        this.props.history.push('/home#/himnos')
      }).catch((err) => {
        console.log(err)
      })
      console.log('LOGIN SUCCESSFUL')
    } else {
      this.setState({
        snack: true
      })
    }
  }
  
  handleChange = event => {
    this.setState({
      [event.target.id]: event.target.value
    });

   
  }

  handleClose = (event, reason) => {
    if (reason === 'clickaway') {
      return;
    }
    this.setState({ snack: false });
  };
 
 


  render(){
    // if (this.state.user) {
    //   <Redirect to='/home' />
    // }

    const { classes, theme } = this.props;
      return (
        <main className={classes.main}>
        <Snack snack={this.state.snack} handleClose={this.handleClose} message="Email format is incorrect!"/>
          <CssBaseline />
          <Paper className={classes.paper}>
            <Avatar className={classes.avatar}>
              <PersonAddRounded />
            </Avatar>
            <Typography component="h1" variant="h5" >
              Sign Up
            </Typography>
            <form className={classes.form}>
            <FormControl margin="normal" required fullWidth onChange={this.handleChange} value={this.state.email}>
                <InputLabel htmlFor="name">Name</InputLabel>
                <Input id="name" name="email" autoComplete="name" autoFocus />
              </FormControl>
              <FormControl margin="normal" required fullWidth onChange={this.handleChange} value={this.state.email}>
                <InputLabel htmlFor="email">Email Address</InputLabel>
                <Input id="email" name="email" autoComplete="email" autoFocus />
              </FormControl>
              <FormControl margin="normal" required fullWidth onChange={this.handleChange} value={this.state.password}>
                <InputLabel htmlFor="password">Password</InputLabel>
                <Input name="password" type="password" id="password" autoComplete="current-password" />
              </FormControl>
              {/* <FormControlLabel
                control={<Checkbox value="remember" color="primary" />}
                label="Remember me"
              /> */}
              <Button
                type="button"
                fullWidth
                variant="contained"
                color="primary"
                className={classes.submit}
                onClick={this.signUp}
              >
                Sign Up
              </Button>
              {/* <FacebookLogin
                  appId="260419231517183"
                  autoLoad={false}
                  fields="name,email,picture"
                  // onClick={componentClicked}
                  callback={this.responseFacebook}
                  render={renderProps => (
                    <Button style={{backgroundColor:'#3b5998'}}  type="button" variant="contained" onClick={renderProps.onClick}><FaFacebookF/></Button>
                  )}
                /> */}
                <AuthComp props={this.props}/>
            </form>
            <div style={{display:'flex', flexDirection:'row', marginTop:10}}>
                <Typography> Already have an create account?</Typography>
                <Link to='/' style={{marginLeft:10, fontWeight:'700', fontSize:14, color: theme.palette.secondary.main}}>Login</Link>
            </div>
          

          </Paper>
          
        </main>
      )
  }

}
Login.propTypes = {
  classes: PropTypes.object.isRequired,
  theme: PropTypes.object.isRequired,
  
};

const mapStateToProps = (state) => {
  return {
    route: state.route,
    search: state.search
    // view: ownProps
  }
}

const mapDispatchToProps = (dispatch) => { 
  return {
      SetUser: (value) => {dispatch(SetUser(value))}
  }
}


export default connect(mapStateToProps, mapDispatchToProps)(withStyles(styles, {withTheme: true})(Login))

