import {createStore, applyMiddleware} from 'redux'
import {persistStore, persistReducer} from 'redux-persist'
import thunkMiddleware from 'redux-thunk'
import storage from 'redux-persist/lib/storage';
import firebase from 'firebase'

const persistConfig = {
    key: 'root',
    storage,
  }

const initialState = {
    route: null,
    search: "",
    searchMenu: null,
    global: 'light',
    user: null,
    hymns: [],
    filteredHymns: []
}

const reducer = (state = initialState, action) => {
    switch (action.type) {
        case 'setRouteParams': return {...state, route: action.value}
        case 'setSearch': return {...state, search: action.value}
        case 'handleSearchMenu': return {...state, searchMenu: action.value}
        case 'setGlobalColor': return {...state, global: action.value}
        case 'setUser': return {...state, user: action.value}
        case 'setHymnsList': return {...state, hymns: action.value}
        case 'setfilterFavs': return {...state, filteredHymns: action.value}
        default:
            return state;
    }
}

export const store = createStore(persistReducer(persistConfig, reducer), applyMiddleware(thunkMiddleware))
export const persistor = persistStore(store)

const setRouteParams = (value) => {
    return {
        type:'setRouteParams',
        value: value
    }
}

const setSearch = (value) => {
    return {
        type:'setSearch',
        value: value
    }
}
const handleSearchMenu = (value) => {
    return {
        type:'handleSearchMenu',
        value: value
    }
}

const setGlobal = (value) => {
    return {
        type:'setGlobalColor',
        value: value
    }
}

const setUserData = (value) => {
    return {
        type: 'setUser',
        value: value
    }
}

// const setFireHymnsList = (value) => {
//     return {
//         type:'setHymnsList',
//         value: value
//     }
// }
function SetUser(params) {
    return function(dispatch){
        dispatch(setUserData(params))
    }
}

function settingRouteParams(params){
    return function (dispatch){
        dispatch(setRouteParams(params))
    }
}

function setSearchResult(search){
    return function (dispatch){
        dispatch(setSearch(search))
    }
}

function setGlobalTheme(theme){
    return function (dispatch){
        dispatch(setGlobal(theme))
    }
}

const filterFavs = () => async dispatch => {
    var hymnsfiltered = store.getState().hymns.filter((val) => {
        for(var p in val.users){
            return val.users[p].uid.match(store.getState().user.uid)
        }
    })
    dispatch({
        type:'setfilterFavs',
        value: hymnsfiltered
    })
}

const getFireHymns = () => async dispatch => {
    var arr =[]
    firebase.database().ref(`himnos`).on('value', snapshot => {
        dispatch({
            type:'setHymnsList',
            value: snapshot.val()
        })
        if(store.getState().user){
            dispatch(filterFavs())
        }
    })
}



export {
    settingRouteParams,
    setSearchResult,
    setGlobalTheme,
    SetUser,
    getFireHymns,
    filterFavs
}