class SearchAppBar extends React.Component {

  constructor(props){
    super(props) 

    this.state = {
      searchOn: false
    }

    this.textInput = React.createRef();

    this.autocompleteSearchDebounced = debounce(500, this.filteredSearch);
    this.autocompleteSearchThrottled = throttle(500, this.filteredSearch);

  }

      removeDiacritics(str) {

        var defaultDiacriticsRemovalMap = [
          {'base':'A', 'letters':/[\u0041\u24B6\uFF21\u00C0\u00C1\u00C2\u1EA6\u1EA4\u1EAA\u1EA8\u00C3\u0100\u0102\u1EB0\u1EAE\u1EB4\u1EB2\u0226\u01E0\u00C4\u01DE\u1EA2\u00C5\u01FA\u01CD\u0200\u0202\u1EA0\u1EAC\u1EB6\u1E00\u0104\u023A\u2C6F]/g},
          {'base':'E', 'letters':/[\u0045\u24BA\uFF25\u00C8\u00C9\u00CA\u1EC0\u1EBE\u1EC4\u1EC2\u1EBC\u0112\u1E14\u1E16\u0114\u0116\u00CB\u1EBA\u011A\u0204\u0206\u1EB8\u1EC6\u0228\u1E1C\u0118\u1E18\u1E1A\u0190\u018E]/g},         
          {'base':'I', 'letters':/[\u0049\u24BE\uFF29\u00CC\u00CD\u00CE\u0128\u012A\u012C\u0130\u00CF\u1E2E\u1EC8\u01CF\u0208\u020A\u1ECA\u012E\u1E2C\u0197]/g},       
          {'base':'O', 'letters':/[\u004F\u24C4\uFF2F\u00D2\u00D3\u00D4\u1ED2\u1ED0\u1ED6\u1ED4\u00D5\u1E4C\u022C\u1E4E\u014C\u1E50\u1E52\u014E\u022E\u0230\u00D6\u022A\u1ECE\u0150\u01D1\u020C\u020E\u01A0\u1EDC\u1EDA\u1EE0\u1EDE\u1EE2\u1ECC\u1ED8\u01EA\u01EC\u00D8\u01FE\u0186\u019F\uA74A\uA74C]/g},       
          {'base':'U', 'letters':/[\u0055\u24CA\uFF35\u00D9\u00DA\u00DB\u0168\u1E78\u016A\u1E7A\u016C\u00DC\u01DB\u01D7\u01D5\u01D9\u1EE6\u016E\u0170\u01D3\u0214\u0216\u01AF\u1EEA\u1EE8\u1EEE\u1EEC\u1EF0\u1EE4\u1E72\u0172\u1E76\u1E74\u0244]/g},        
          {'base':'a', 'letters':/[\u0061\u24D0\uFF41\u1E9A\u00E0\u00E1\u00E2\u1EA7\u1EA5\u1EAB\u1EA9\u00E3\u0101\u0103\u1EB1\u1EAF\u1EB5\u1EB3\u0227\u01E1\u00E4\u01DF\u1EA3\u00E5\u01FB\u01CE\u0201\u0203\u1EA1\u1EAD\u1EB7\u1E01\u0105\u2C65\u0250]/g},
          {'base':'e', 'letters':/[\u0065\u24D4\uFF45\u00E8\u00E9\u00EA\u1EC1\u1EBF\u1EC5\u1EC3\u1EBD\u0113\u1E15\u1E17\u0115\u0117\u00EB\u1EBB\u011B\u0205\u0207\u1EB9\u1EC7\u0229\u1E1D\u0119\u1E19\u1E1B\u0247\u025B\u01DD]/g},
          {'base':'i', 'letters':/[\u0069\u24D8\uFF49\u00EC\u00ED\u00EE\u0129\u012B\u012D\u00EF\u1E2F\u1EC9\u01D0\u0209\u020B\u1ECB\u012F\u1E2D\u0268\u0131]/g},
          {'base':'o', 'letters':/[\u006F\u24DE\uFF4F\u00F2\u00F3\u00F4\u1ED3\u1ED1\u1ED7\u1ED5\u00F5\u1E4D\u022D\u1E4F\u014D\u1E51\u1E53\u014F\u022F\u0231\u00F6\u022B\u1ECF\u0151\u01D2\u020D\u020F\u01A1\u1EDD\u1EDB\u1EE1\u1EDF\u1EE3\u1ECD\u1ED9\u01EB\u01ED\u00F8\u01FF\u0254\uA74B\uA74D\u0275]/g},         
          {'base':'u','letters':/[\u0075\u24E4\uFF55\u00F9\u00FA\u00FB\u0169\u1E79\u016B\u1E7B\u016D\u00FC\u01DC\u01D8\u01D6\u01DA\u1EE7\u016F\u0171\u01D4\u0215\u0217\u01B0\u1EEB\u1EE9\u1EEF\u1EED\u1EF1\u1EE5\u1E73\u0173\u1E77\u1E75\u0289]/g},
        ];
      
        for(var i=0; i<defaultDiacriticsRemovalMap.length; i++) {
          str = str.replace(defaultDiacriticsRemovalMap[i].letters, defaultDiacriticsRemovalMap[i].base);
        }
      
        return str;
      
      }

      handleChange = event => {
        this.props.setSearch(event.target.value)
        this.setState({
          [event.target.id]: event.target.value
        }, () => {
          if(this.props.search.length < 5) {
            this.autocompleteSearchThrottled(this.props.search);
          } else {
            this.autocompleteSearchDebounced(this.props.search);
          }
        });
      }

      filteredSearch = (search) => {
          filterData = this.props.hymns.filter((val) => {
            return this.removeDiacritics(val.title).toLowerCase().match(search) || val.number.toString().match(search)

          })
      };

   

      render(){
        store.subscribe(handleGlobal)

        var searchOn  = false
        if(this.props.search) {
          searchOn = true
        } else {
          searchOn = false
        } 
       
     
       const { classes, route } = this.props;
       
           return (
            <div className={classes.root}>
            <AppBar position="fixed" id="Search_Bar"
                className={classNames(classes.appBar, {
                    [classes.appBarShift]: this.props.parentState,
                })}>
                <Toolbar disableGutters={!this.props.parentState}>
                <IconButton
                    color="inherit"
                    aria-label="Open drawer"
                    onClick={this.props.open}
                    className={classNames(classes.menuButton, {
                        [classes.hide]: this.props.parentState,
                    })}
                    >
                    <MenuIcon />
                    </IconButton>
                {/* <Drawer/> */}
                <Typography className={classes.title} variant="h6" color="inherit" noWrap>
                    Himnos
                </Typography>
                  { route ?  <Typography className={classes.hymntitle} color="inherit" noWrap>
                    {route.title}
                </Typography> : null}
                {/* .substring(0, match.params.title.indexOf('(')) */}
                <div className={classes.grow} />
                <div className={classes.search} >
                    <div className={classes.searchIcon}>
                    <FaSearch style={{color: currentValue === 'light' ? '#222' : '#fff'}}/>
                    </div>
                      <InputBase
                        // onFocus={()=> this.setState({searchOn: true})}
                        // onBlur={()=> this.setState({searchOn: false})}
                        inputRef={input => (this.tf = input)}
                        placeholder="Search…"
                        onChange={this.handleChange.bind(this)} value={this.props.search}
                        classes={{
                            root: classes.inputRoot,
                            input: classes.inputInput,
                        }}
                    >
                    </InputBase> 
                 
                </div>
            
                <div style={{marginRight:20, position:'relative'}}>
                {this.props.search ? 
                      <IconButton className={classes.close} color="inherit" onClick={()=>this.props.setSearch("")}> 
                          <FaTimes size={20} />
                      </IconButton>
                    //  <Fab size="small" onClick={()=>this.props.setSearch("")} style={{marginLeft:-10}}>
                    //     <FaTimes   style={{color: currentValue === 'light' ? '#222' : '#fff'}} /> 
                    //  </Fab> 
                     : null}
                    <Button onClick={() => {
                            firebase.auth().signOut().then(() => {
                                ls.remove('user')
                                this.props.props.history.push('/')
                            })
                        }} >Logout</Button>
                </div>
                </Toolbar>
      </AppBar>
      { searchOn ? 
      <SearchMenu list={filterData} /> : null
      }
    </div>
          )
      }
    
}

SearchAppBar.propTypes = {
  classes: PropTypes.object.isRequired,
  theme: PropTypes.object.isRequired,

};

const mapStateToProps = (state) => {
  return {
    route: state.route,
    search: state.search,
    global: state.global,
    hymns: state.hymns
    // view: ownProps
  }
}


const mapDispatchToProps = (dispatch) => { 
  return {
      setSearch: (value) => {dispatch(setSearchResult(value))},
  }
}



export default connect(mapStateToProps, mapDispatchToProps)(withStyles(styles, { withTheme: true })(SearchAppBar));
