import React, { Component } from "react";
import PropTypes from 'prop-types';
import { withStyles } from '@material-ui/core/styles';
import {Typography, Fab, Grid, Paper, IconButton} from '@material-ui/core';
import {ZoomIn, ZoomOut, Clear, ArrowBackRounded ,Favorite, FavoriteBorder} from '@material-ui/icons';
import {connect} from 'react-redux'
import { settingRouteParams} from '../store'
import Modal from './Modal'
import firebase from 'firebase'

const styles = theme => ({
    root: {
      flexGrow: 1,
    },
    paper: {
      padding: theme.spacing.unit * 2,
      margin: theme.spacing.unit * 2,
      textAlign: 'center',
      color: theme.palette.text.secondary,
    
    },
    lowerCardCont: {
        [theme.breakpoints.up('sm')]: {
            marginLeft: 75
          },
    },
    lowerCard: {
        marginLeft:10,
        [theme.breakpoints.down('sm')]: {
            fontSize: 12
          },
          [theme.breakpoints.up('sm')]: {
            fontSize: 24
          },
    }
    // card: {
    //     margin: theme.spacing.unit * 2, 
    // }
  });
  
class Hymn extends Component {
    
    constructor(props) {
        super(props)
        this.state = {
            zoom: 1,
            moveMargin: 0
        }

    }

    handleOpen = () => {
        this.setState({ open: true });
      };
    
      handleClose = () => {
        this.setState({ open: false });
      };
    

    zoom(num){
        this.setState({
            zoom: this.state.zoom + num
        })
        // console.log(this.state.zoom)
        // if(num > 0) {
        //     if(this.state.zoom > 1){
        //         this.setState({moveMargin: this.state.moveMargin + 10})
        //     }
        // }
    }
    removeFromFavDatabase(){
        firebase.database().ref(`himnos/${this.props.match.params.number}/users/${this.props.user.uid}`).remove()

    }

    addToFavDatabase(){
        firebase.database().ref(`himnos/${this.props.match.params.number}`).child(`users/${this.props.user.uid}`).set(
            {
                uid: this.props.user.uid,
                name: this.props.user.name
            }
        ) 
    }
      
    render() {
        const { match, classes, history} = this.props

        var isFavs = false
        this.props.filteredHymns.map((val) => {
            if(val.number == match.params.number) {
                isFavs = true
            }
        })

        // const matches = useMediaQuery('print');
        // console.log(this.props)
        const imageUrl = `/himnos/himno_${match.params.number}.jpg`
    
        // const matchesXs = useMediaQuery(theme.breakpoints.up('xs'));

        // console.log(matches)

        return (
            <div className={classes.root}>
                <div style={{position:'fixed', zIndex:9999, top: 80, right: 20}}>
                    {this.state.zoom < 1 || this.state.zoom > 1 ? 
                        <Fab onClick={ () => this.setState({zoom: 1})} size="medium" color="primary" aria-label="Clear" className={classes.fab}>
                            <Clear />
                        </Fab> : null
                    }
                    <Fab onClick={() => this.zoom(.1)} size="medium" color="primary" style={{marginLeft:10}} aria-label="ZoomIn" className={classes.fab}>
                        <ZoomIn />
                    </Fab>
                    <Fab onClick={ () => this.zoom(-.1)} size="medium" color="primary" style={{marginLeft:10}} aria-label="ZoomOut" className={classes.fab}>
                        <ZoomOut />
                    </Fab>
                </div>
                <div style={{position:'fixed', zIndex:999, left: 70, top: 70}}>
                    <Fab onClick={ () => [history.goBack(), this.props.settingRouteParams(null)]} size="medium" color="primary" style={{marginLeft:10}} aria-label="ZoomOut" className={classes.fab}>
                        <ArrowBackRounded />
                    </Fab>
                </div>

                <div style={{position:'fixed', zIndex:9998, left: 10, bottom: 10}}>
                <Grid item xs={12} >
                    <Paper className={classes.lowerCardCont} style={{ display: 'flex', flexDirection:'row', justifyContent:'center', alignItems:'center'}}>
                            <Typography className={classes.lowerCard}>
                                {match.params.title.substring(0, match.params.title.indexOf('('))}
                            </Typography>
                            { isFavs ? 
                            
                            <IconButton  aria-label="Favorite" style={{marginLeft:10}} onClick={()=> this.removeFromFavDatabase()}>
                                <Favorite color="primary" /> 
                            </IconButton> 
                         : 
                            <IconButton  aria-label="Favorite" style={{marginLeft:10}} onClick={()=> this.addToFavDatabase()}>
                                <FavoriteBorder  /> 
                            </IconButton> 
                         
                         }
                    </Paper>

                </Grid>
                </div>
                    <Grid container justify='center' alignItems='center'>
                        <Grid container item xs={12} md={10} lg={8} >
                          
                            <Paper className={classes.paper}>
                                    <img src={imageUrl} width="100%" height="auto" alt=""
                                    style={{transform: `scale(${this.state.zoom})`}}
                                    />
                            </Paper>
                           
                        </Grid>
                    </Grid>

                    <Modal/>
                </div>
          
        );
    }
}

Hymn.propTypes = {
    classes: PropTypes.object.isRequired,
    theme: PropTypes.object.isRequired,
  };

  const mapStateToProps = (state) => {
    return {
      route: state.route,
      filteredHymns: state.filteredHymns,
      user: state.user
      // view: ownProps
    }
  }

const mapDispatchToProps = (dispatch) => { 
    return {
        settingRouteParams: (value) => {dispatch(settingRouteParams(value))}
    }
}


export default connect(mapStateToProps, mapDispatchToProps)(withStyles(styles, {withTheme: true})(Hymn));

