import React, { Component } from "react";
import { List, ListItem, ListItemText, Divider, Typography} from '@material-ui/core'
import { connect } from 'react-redux'
import { settingRouteParams, setSearchResult} from '../store'
import { withStyles } from '@material-ui/core/styles';
import PropTypes from 'prop-types';
import Highlighter from "react-highlight-words";

import {Link } from 'react-router-dom'

const styles = theme => ({
    item : {
        [theme.breakpoints.down('xs')]: {
            fontSize: 12
          },
    },
    itemNum:{
        fontWeight:'700'
    },
    highlight :{
        color:'#000'
    }
})

class HymnListSearch extends Component {

    constructor(props){
        super(props)
        this.state = {
            loading: true
        }
    }



   

    render() {
        const { search, classes, theme } = this.props
        return (
            <div style={{marginTop:4}}> 
                <List>
                    {this.props.list.map((val, i) => {
                        return (
                            <div key={i}>
                            { val.title  ? 
                            <div>
                                <Link to={ {
                                    pathname: `/${val.title}/${val.number}`,
                                    state: val
                                }} style={{ textDecoration: 'none' }} onClick={()=>[this.props.settingRouteParams(val), this.props.setSearchResult("")]}>
                                    <ListItem>

                                            {/* <div style={{alignSelf:'center'}}>
                                                <ListItemText  primary={<Typography className={classes.itemNum}>{ val.number}</Typography>}/>
                                            </div> */}
                                   
                                     <Highlighter
                                     highlightStyle={{
                                         color: '#828282' ,
                                         backgroundColor: theme.palette.primary.main
                                
                                     }}
                                     unhighlightStyle={{
                                         color: '#828282',
                                         fontWeight:"200"
                                     }}
                                     searchWords={[this.props.search]}
                                     autoEscape={true}
                                     textToHighlight={val.number + " - " + val.title}
                                     > 
                                     </Highlighter>
                                            {/* <ListItemText  primary={ <Typography className={classes.item}>{ val.title}</Typography>}/> */}
                                            {/* <ListItemText  primary={ <Typography className={classes.item}>{ val.title}</Typography>}/> */}
                                    </ListItem>
                                </Link>
                                <Divider variant="middle" />
                            </div>
                            : null}
                            </div>
                        )
                    })  }
                </List>
            </div>

        );
    }
}
const mapStateToProps = (state) => {
    return {
      route: state.route,
      search: state.search,
      hymns: state.hymns,
      global: state.global
      // view: ownProps
    }
  }

const mapDispatchToProps = (dispatch) => { 
    return {
        settingRouteParams: (value) => {dispatch(settingRouteParams(value))},
        setSearchResult: (value) => {dispatch(setSearchResult(value))}
    }
}

HymnListSearch.propTypes = {
    classes: PropTypes.object.isRequired,
    theme: PropTypes.object.isRequired,
  
  };
  
export default connect(mapStateToProps, mapDispatchToProps)(withStyles(styles, {withTheme: true})(HymnListSearch));

