import React, { Component } from 'react';
import firebase from 'firebase';
import config from './firebase/index'
import './App.css';
import Home from './screens/Home'
import {BrowserRouter, Route, Redirect, Switch} from 'react-router-dom'
import {ProtectedRoute} from './protected.route'
import { hot } from 'react-hot-loader/root'
import { Provider } from 'react-redux'
import {store, persistor, setGlobalTheme, getFireHymns, filterFavs} from './store'
import { PersistGate } from 'redux-persist/integration/react'
import Login from './components/Auth/LoginComp'
import SignUp from './components/Auth/SignUpComp'
import {
  Paper,Button
} from '@material-ui/core'
import { MuiThemeProvider, createMuiTheme } from '@material-ui/core/styles';
import {WbSunnyRounded, Brightness3Rounded}from '@material-ui/icons';
import {FaMoon, FaSun} from 'react-icons/fa'

let currentValue



class App extends Component {
  constructor(props){
    super(props)
    this.state = {
      global : 'light'
    }
    firebase.initializeApp(config.firebaseConfig)

    this.handleChange = this.handleChange.bind(this);
   
  }
  componentWillMount(){
    store.dispatch(getFireHymns())
  }
  


  handleChange(){
      
      let previousValue = currentValue
      currentValue = store.getState().global
   

      if (previousValue !== currentValue) {
        this.setState({
          global: currentValue
        })
      }
   
  }

  render() {
  
    store.subscribe(this.handleChange)

    var theme = createMuiTheme({
      // typography: {
      //   fontFamily: {
      //     ''
      //   }
      // },
      palette: {
        type: this.state.global,
        primary: {
          main:'#4dd0e1'
        },
        secondary: {
            main: '#00acc1'
          }
        }
      }
    )
  

    return (
      <Provider store={store}>
            <PersistGate loading={null} persistor={persistor}>
              <BrowserRouter>
              <MuiThemeProvider theme={theme}>
              <div style={{ height: '100vh'}}>
                <Switch>
                  <Route exact path='/' component={Login}/>
                  <Route exact path='/signup' component={SignUp}/>
                  <ProtectedRoute exact path='/home' component={Home}/>
                  <Route path="*" component={()=> '404 NOT FOUND'}/>
                </Switch>

                <Paper style={{display:'flex', backgroundColor:'#595959', width: 140, padding: 5, justifyContent:'space-around', position:'fixed', bottom: 10, right: 10}}>
                  <Button color="primary"  onClick={()=> store.dispatch(setGlobalTheme('light'))}>
                    <FaSun style={{color: "rgba(255,255,0, 1)"}} size={20}/>
                  </Button>
                  <Button color="primary" onClick={()=> store.dispatch(setGlobalTheme('dark'))}>
                    <FaMoon style={{color: "rgba(200,180,255, 1)"}} size={20}/>
                  </Button>
                </Paper>
              </div>
              </MuiThemeProvider>
              </BrowserRouter>
        </PersistGate>
      </Provider>
    );
  }
}

export default hot(App);
