import React, {Component} from 'react';
import PropTypes from 'prop-types';
import {Grid, Button} from '@material-ui/core';
import {FaFacebookF, FaGooglePlusG} from 'react-icons/fa'
import firebase from 'firebase';
import withStyles from '@material-ui/core/styles/withStyles';
import ls from 'local-storage';
import {SetUser} from '../../store'
import {connect} from 'react-redux'


const styles = theme => ({})


class AuthComp extends Component {

    Auth(auth){

        var that = this;
        var provider = null;
        if(auth === 'facebook') provider = new firebase.auth.FacebookAuthProvider()
        else if( auth === 'gmail') provider = new firebase.auth.GoogleAuthProvider()

        
    
        firebase.auth().signInWithPopup(provider).then(function(result) {
            var user = result.user;
            var obj = {
                uid: user.uid,
                name: user.displayName,
                email: user.providerData[0].email,
                emailVerified: user.emailVerified,
                profile_picture: user.photoURL,
            }

            

          firebase.database().ref('users').orderByChild("uid").equalTo(user.uid).once('value', snapshot => {
            if(snapshot.exists()){
              console.log('ALREADY EXISTS')
              ls.set('user', user)
              that.props.SetUser(obj)
                that.props.props.history.push('/home#/himnos')
            } else {
              console.log('CREATING NEW KEY')
                firebase.database().ref('users').child(user.uid).set(obj)
                ls.set('user', user)
                that.props.SetUser(obj)
                that.props.props.history.push('/home#/himnos')
        }
          })
         
        }).catch(function(error) {
          console.log(error)
        });
    
      }

      
    render(){

        return (
            <div style={{flexGrow:1, marginTop: 20}}>
                <Grid 
                    container
                    spacing={8}
                    direction="row"
                    alignItems="center"
                    justify="center">
                    <Grid item xs={4}>
                        <Button type="button"  style={{backgroundColor:'#DB4437', color:'#fff', height:50, width:'100%'}} onClick={() => this.Auth('gmail')}><FaGooglePlusG size={30}/></Button>
                    </Grid>
                    <Grid item xs={4}>
                        <Button type="button"  style={{backgroundColor:'#3b5998', color:'#fff', height:50, width:'100%'}}  onClick={() => this.Auth('facebook')}><FaFacebookF size={20}/></Button>
                    </Grid>
                </Grid>
            </div>
        )
    }
}

AuthComp.propTypes = {
    classes: PropTypes.object.isRequired,
  };

  const mapStateToProps = (state) => {
    return {
      route: state.route,
      search: state.search
      // view: ownProps
    }
  }
  
  const mapDispatchToProps = (dispatch) => { 
    return {
        SetUser: (value) => {dispatch(SetUser(value))}
    }
  }

export default connect(mapStateToProps, mapDispatchToProps)(withStyles(styles)(AuthComp))