import React, { Component } from "react";
import { List, ListItem, ListItemText, LinearProgress, IconButton, Divider, Typography} from '@material-ui/core'
import {FavoriteBorder, Favorite} from '@material-ui/icons'
import { connect } from 'react-redux'
import { settingRouteParams} from '../store'
import firebase from 'firebase'
import {Link } from 'react-router-dom'
import { type } from "os";
import { withStyles } from '@material-ui/core/styles';
import PropTypes from 'prop-types';
import classNames from 'classnames';

const styles = theme => ({
   title: {
    [theme.breakpoints.up('sm')]: {
        marginLeft: 50
      }
   }
})
class HymnList extends Component {
    _isMounted = false

    constructor(props){
        super(props)
        this.state = {
            loading: true,
        }
    }
 
  

    removeFromFavDatabase(val, hymn){
        // console.log(hymn)
        firebase.database().ref(`himnos/${hymn.number}/users/${this.props.user.uid}`).remove()
    }

    addToFavDatabase(val){
        // var key = firebase.database().ref(`himnos/${val.number}`).child('users').push().key
        firebase.database().ref(`himnos/${val.number}`).child(`users/${this.props.user.uid}`).set(
            {
                // key: key,
                uid: this.props.user.uid,
                name: this.props.user.name
            }
        ) 
    }

  


    _renderObject(obj, hymn){

            var filterUserSaves = Object.entries(obj).filter(([key, value], i) => { 
                return value.uid.match(this.props.user.uid)
            })

            if(filterUserSaves.length !== 0){
                return(
                    <IconButton  aria-label="Favorite" onClick={()=> this.removeFromFavDatabase(filterUserSaves[0], hymn)}>
                        <Favorite color="primary" /> 
                        </IconButton> 
                        )
            } else {
                return (
                    <IconButton  aria-label="FavoriteBorder" onClick={()=> this.addToFavDatabase(hymn)}>
                        <FavoriteBorder />
                    </IconButton> 
                    )
            }

        
	}

    render() {
        const {theme, classes} = this.props
        return (
            <div style={{paddingTop:65}}> 
                {/* {this.state.loading ? <LinearProgress/> : null } */}
                {this.props.hymns ?             
                <List>
                    {this.props.hymns.map((val, i) => {
                        return (
                            <div key={i}>
                            { val.title  ? 
                            <div>
                                    <ListItem>
                                        <ListItemText  primary={<Typography className={classes.title} style={{fontWeight:'700', color: theme.palette.primary.main, fontSize:18}}>{val.number}</Typography>} style={{fontWeight:'bold'}}/>
                                            <Link to={ {
                                                pathname: `/${val.title}/${val.number}`,
                                                state: val
                                            }} style={{ textDecoration: 'none', width:'100%' }} onClick={()=>this.props.settingRouteParams(val)}>
                                            <div style={{alignSelf:'center'}}>
                                            </div>
                                            <ListItemText primary={val.title}/>
                                             </Link>
                                             { val.users ?
                                             this._renderObject(val.users, val)
                                                 : 
                                            
                                            <IconButton aria-label="FavoriteBorder" onClick={()=> this.addToFavDatabase(val)}>
                                                 <FavoriteBorder />
                                             </IconButton> }           
                                    </ListItem>
                                <Divider variant="middle"/>
                            </div>
                            : null}
                            </div>
                        )
                    })  }
                </List>
                :
                <LinearProgress/>
            }
            </div>

        );
    }
}
const mapStateToProps = (state) => {
    return {
      route: state.route,
      search: state.search,
      user: state.user,
      hymns: state.hymns
      // view: ownProps
    }
  }

const mapDispatchToProps = (dispatch) => { 
    return {
        settingRouteParams: (value) => {dispatch(settingRouteParams(value))},
        // setHymns: (value) => {dispatch(setHymns(value))}
    }
}
HymnList.propTypes = {
    classes: PropTypes.object.isRequired,
    theme: PropTypes.object.isRequired,
  
  };

  

export default connect(mapStateToProps, mapDispatchToProps)(withStyles(styles, {withTheme: true})(HymnList));
