import React, {Component} from 'react';
import PropTypes from 'prop-types';
import Avatar from '@material-ui/core/Avatar';
import Button from '@material-ui/core/Button';
import CssBaseline from '@material-ui/core/CssBaseline';
import FormControl from '@material-ui/core/FormControl';
import FormControlLabel from '@material-ui/core/FormControlLabel';
import Checkbox from '@material-ui/core/Checkbox';
import Input from '@material-ui/core/Input';
import InputLabel from '@material-ui/core/InputLabel';
import LockOutlinedIcon from '@material-ui/icons/LockOutlined';
import Paper from '@material-ui/core/Paper';
import Typography from '@material-ui/core/Typography';
import withStyles from '@material-ui/core/styles/withStyles';
import {Link} from 'react-router-dom'
import ls from 'local-storage'
import AuthComp from './AuthComp'
import firebase from 'firebase';
import { withTheme } from '@material-ui/styles';
import {SetUser} from '../../store'
import {connect} from 'react-redux'

// const { classes } = props;

const styles = theme => ({
  main: {
    width: 'auto',
    display: 'block', // Fix IE 11 issue
    marginLeft: theme.spacing.unit * 3,
    marginRight: theme.spacing.unit * 3,
    [theme.breakpoints.up(400 + theme.spacing.unit * 3 * 2)]: {
      width: 400,
      marginLeft: 'auto',
      marginRight: 'auto',
    },
  },
  paper: {
    marginTop: 90,
    display: 'flex',
    flexDirection: 'column',
    // backgroundColor:'#333',
    alignItems: 'center',
    padding: `${theme.spacing.unit * 2}px ${theme.spacing.unit * 3}px ${theme.spacing.unit * 3}px`,
  },
  avatar: {
    margin: theme.spacing.unit,
    backgroundColor: theme.palette.secondary.main,
  },
  form: {
    width: '100%', // Fix IE 11 issue.
    marginTop: theme.spacing.unit,
  },
  submit: {
    marginTop: theme.spacing.unit * 3,
    backgroundColor: theme.palette.secondary.main
  }
});

class LogIn extends Component {
  
  constructor(props) {
    super(props)
    this.state = {
      email: '',
      password: '',
      user: false
    }

  }
  componentDidMount(){
    if(ls.get('user')) {
      this.props.history.push('/home#/himnos')
    } 
  }

  login = () => {
    if(this.state.email && this.state.password)
    firebase.auth().signInWithEmailAndPassword(this.state.email, this.state.password).then((res)=> {
      console.log(res)
      ls.set('user', res)
      this.props.SetUser(res)
      this.props.history.push('/home#/himnos')
    }).catch((err) => {
      console.log(err)
    })
    console.log('LOGIN SUCCESSFUL')
  }
  
  handleChange = event => {
    this.setState({
      [event.target.id]: event.target.value
    });

   
  }

  render(){
    // if (this.state.user) {
    //   <Redirect to='/home' />
    // }
    const { classes, theme } = this.props;
      return (
        <main className={classes.main}>
          <CssBaseline />
          <Paper className={classes.paper}>
            <Avatar className={classes.avatar}>
              <LockOutlinedIcon />
            </Avatar>
            <Typography component="h1" variant="h5" >
              Login
            </Typography>
            <form className={classes.form}>
              <FormControl margin="normal" required fullWidth onChange={this.handleChange} value={this.state.email}>
                <InputLabel htmlFor="email" className={classes.input}>Email Address</InputLabel>
                <Input id="email" name="email" autoComplete="email" autoFocus />
              </FormControl>
              <FormControl margin="normal" required fullWidth onChange={this.handleChange} value={this.state.password}>
                <InputLabel htmlFor="password" className={classes.input}>Password</InputLabel>
                <Input name="password" type="password" id="password" autoComplete="current-password" />
              </FormControl>
              <FormControlLabel
                control={<Checkbox value="remember" color="primary" />}
                label="Remember me"
              />
              <Button
                type="button"
                fullWidth
                variant="contained"
                className={classes.submit}
                onClick={this.login}
              >
                Sign in
              </Button>
              <AuthComp props={this.props}/>
            </form>           
            <div style={{display:'flex', flexDirection:'row', marginTop:10}}>
                <Typography> Need to create account?</Typography>
                <Link to='/signup' style={{marginLeft:10, fontWeight:'700', fontSize:12, color: theme.palette.secondary.main}}>Sign Up</Link>
            </div>

          </Paper>
        </main>
      )
  }

}
LogIn.propTypes = {
  classes: PropTypes.object.isRequired,
  theme : PropTypes.object.isRequired
};

const mapStateToProps = (state) => {
  return {
    route: state.route,
    search: state.search
    // view: ownProps
  }
}

const mapDispatchToProps = (dispatch) => { 
  return {
      SetUser: (value) => {dispatch(SetUser(value))}
  }
}

export default connect(mapStateToProps, mapDispatchToProps)(withStyles(styles, {withTheme: true})(LogIn))

