import React, { Component } from "react";
import firebase from 'firebase'
import {List, ListItemText, IconButton, ListItem, Divider} from '@material-ui/core'
import {Favorite, FavoriteBorder, Delete} from '@material-ui/icons'
import {Link} from 'react-router-dom'
import {connect} from 'react-redux'
import {filterFavs, settingRouteParams} from '../store'
var data = require('../himnos.json')

class Favs extends Component {

    constructor(props){
        super(props)

    }

    removeFromFavDatabase(val, hymn){
        console.log(val)
        firebase.database().ref(`himnos/${hymn.number}/users/${this.props.user.uid}`).remove()

    }


    _renderObject(obj, hymn){

        var filterUserSaves = Object.entries(obj).filter(([key, value], i) => { 
            return value.uid.match(this.props.user.uid)
        })

        if(filterUserSaves.length !== 0){
            return(
                <IconButton  aria-label="FavoriteBorder" onClick={()=> this.removeFromFavDatabase(filterUserSaves[0][1], hymn)}>
                        <Delete /> 
                    </IconButton>
                    )
        }

		// return Object.entries(obj).map(([key, value], i) => {
        //     if(value.uid == this.props.user.uid){
        //         return(
        //             <IconButton key={i} aria-label="FavoriteBorder" onClick={()=> this.removeFromFavDatabase(value, hymn)}>
        //                 <Delete /> 
        //             </IconButton>
        //         )
        //     } 
		// })
	}

    render() {
        const { filteredHymns } = this.props

        return (
            <div style={{marginTop:70}}>
                {filteredHymns.length !== 0 ?
                <List>
                    { filteredHymns.map((val, i) => {
                        return (
                            <div key={i}>
                            { val.title  ? 
                            <div>
                                    <ListItem>
                                        <ListItemText  primary={val.number} style={{fontWeight:'bold'}}/>
                                            <Link to={ {
                                                 pathname: `/${val.title}/${val.number}`,
                                                state: val
                                            }} style={{ textDecoration: 'none', width:'100%' }} onClick={()=>this.props.settingRouteParams(val)}>
                                            <div style={{alignSelf:'center'}}>
                                            </div>
                                            <ListItemText primary={val.title}/>
                                             </Link>
                                           {  this._renderObject(val.users, val)}

                                    </ListItem>
                                <Divider variant="middle"/>
                            </div>
                            : null}
                            </div>
                        )
                    })  }
                </List>
                :
                <h1>No Favorites yet!</h1>  
            }   
            </div>
        );
    }
}

const mapStateToProps = (state) => {
    return {
      route: state.route,
      user: state.user,
      hymns: state.hymns,
      filteredHymns: state.filteredHymns

    }
  }

  const mapDispatchToProps = (dispatch) => { 
    return {
        filterFavs: (value) => {dispatch(filterFavs(value))},
        settingRouteParams: (value) => {dispatch(settingRouteParams(value))}
        // setHymns: (value) => {dispatch(setHymns(value))}
    }
}

export default connect(mapStateToProps, mapDispatchToProps)(Favs);

const styles = theme => ({
    container: {
        flex: 1,
        alignItems: 'center',
        justifyContent: 'center'
    }
});